document.addEventListener("DOMContentLoaded",()=>{document.addEventListener("change",e=>{if(e.target.classList.contains("ban-select")){const t=e.target,n=t.closest("form").querySelector(".ban-confirm-button");n&&(n.style.display=t.value?"inline-block":"none")}}),document.addEventListener("click",async e=>{if(e.target&&e.target.classList.contains("view-parent-comment")){e.preventDefault();const t=e.target,n=t.dataset.commentId,o=t.closest(".comment-meta"),a=o.querySelector(".parent-comment-preview")||o.nextElementSibling;if(!a||!a.classList.contains("parent-comment-preview"))return void console.error("Preview container not found");if("none"!==a.style.display)return void(a.style.display="none");if("true"===a.dataset.loaded)return void(a.style.display="block");a.innerHTML="Loading...",a.style.display="block";try{const e=await fetch(`/moderation/api/comment/${n}`);if(!e.ok)throw new Error("Failed to load comment");const t=await e.json(),o=t.is_removed?"[removed]":t.content,r=t.username||"[removed]";a.innerHTML=`\n                    <div style="font-size: 0.9em; margin-bottom: 5px;">\n                        <strong><a href="/user/${r}">${r}</a></strong> said:\n                    </div>\n                    <div>${o}</div>\n                `,a.dataset.loaded="true"}catch(e){a.innerHTML=`<span style="color: red;">Error: ${e.message}</span>`}}})});